  const live = new Set(cells.map(([x, y]) => `${x},${y}`));
  // Invocations: new Set(1), cells.map(1) → 2 invocations
  // Bindings: live(1), x(1), y(1) → 3 bindings

  const neighborCounts = new Map<string, number>();
  // Invocations: new Map(1) → 1 invocation
