      // Template literal: building string → 
      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      // Invocations: neighborCounts.get(1), .set(1), + (addition, counted above), ?? → 
      // Let me count .set as 1, .get as 1, ?? as 1 conditional
      // Assignment: set is mutation → 1 assignment
    }
  }

  const result: Cell[] = [];
  // Binding: result(1)

  for (const [x, y] of cells) {
    // Loop: 1
    // Bindings: x(1), y(1)
    const count = neighborCounts.get(`${x},${y}`) ?? 0;
    // Binding: count(1)
