    if (count === 2 || count === 3) {
      // Conditionals: ===(2), ||(1) → 3 conditionals
      result.push([x, y]);
      // Invocation: .push(1)
    }
  }

  for (const [key, count] of neighborCounts) {
    // Loop: 1
    // Bindings: key(1), count(1)
    if (count === 3) {
      // Conditional: 1
      const [xStr, yStr] = key.split(",");
      // Bindings: xStr(1), yStr(1)
      // Invocation: .split(1)
      const x = parseInt(xStr);
